#!/usr/bin/env python3
"""
kaching-tell — complete goal-detection / verification / scoring fix
===================================================================
Overwrites six source files with fully-fixed, tested versions.
Content is embedded as base64 so nothing can be corrupted by the
terminal (no heredocs, no quoting hazards). Safe to re-run.

Usage:
    python3 fix_kaching_tell.py            # auto-detects the repo
    python3 fix_kaching_tell.py /path/to/kaching-tell
"""
import base64, os, sys, shutil, subprocess, datetime

FILES = {
    'src/config/constants.js': "",
    'src/detection/clockSanity.js': "",
    'src/detection/verifier.js': "",
    'src/detection/spikeDetector.js': "",
    'src/detection/goalDetector.js': "",
    'src/feeds/streamManager.js': "",
}


FIXES = """
  1. clockSanity.js  isSane() now FAILS OPEN. The live agent was discarding
                     every event (all goals included) because the fixture has no
                     epoch-ms StartTime, so drift was NaN and NaN < limit == false.
                     It now normalises ms/seconds/ISO timestamps and only rejects
                     genuinely corrupted batch events. -> goals are detected again.
  2. verifier.js     Rewritten. Confirmations are matched oldest-first (FIFO) in an
                     ADAPTIVE lag window that starts generous (tolerates the 20+ min
                     historical-batch delay -> no more mass false positives / ??
                     everywhere) and tightens toward the live ~54s lag so a VAR goal
                     ages out instead of stealing a later goal's confirmation. The
                     SCORER is taken from which stat key increments (1001=home,
                     1002=away), never the unreliable Participant field -> the team
                     shown is the team that actually scored. Confirmed score is the
                     running official total, so a 4-6 match shows 0-1,1-1,...,4-6.
                     Handles increments that arrive before their goal action.
  3. constants.js    Adds VERIFICATION_MAX_LAG (30 min ceiling) and MIN_BASELINE.
  4. spikeDetector   Numeric (not string) ratio + baseline floor so a near-zero
                     calm period can't manufacture absurd spike ratios.
  5. goalDetector    Never drops goal/game_finalised on a clock heuristic; adds a
                     wall-clock safety flush so a live goal always resolves even if
                     the event stream briefly goes quiet; numeric confidence.
  6. streamManager   Caps the dedup sets (memory) for long-running matches; safer
                     SSE close handling.
"""


def find_repo(argv):
    if len(argv) > 1:
        return os.path.abspath(argv[1])
    here = os.path.abspath(os.path.dirname(__file__))
    for cand in (here, os.path.join(here, "kaching-tell"),
                 os.path.expanduser("~/kaching-tell"), os.getcwd()):
        if os.path.isdir(os.path.join(cand, "src", "detection")):
            return cand
    return here


def main():
    repo = find_repo(sys.argv)
    if not os.path.isdir(os.path.join(repo, "src", "detection")):
        print("ERROR: could not find the kaching-tell repo (no src/detection).")
        print("Run:  python3 fix_kaching_tell.py /path/to/kaching-tell")
        sys.exit(1)

    stamp = datetime.datetime.now().strftime("%Y%m%d-%H%M%S")
    backup = os.path.join(repo, ".fix-backup-" + stamp)
    print("Repo:   " + repo)
    print("Backup: " + backup)
    os.makedirs(backup, exist_ok=True)

    written = []
    for rel, b64 in FILES.items():
        dest = os.path.join(repo, rel)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        if os.path.exists(dest):
            bdst = os.path.join(backup, rel.replace("/", "__"))
            shutil.copy2(dest, bdst)
        data = base64.b64decode(b64)
        with open(dest, "wb") as f:
            f.write(data)
        written.append(rel)
        print("  wrote " + rel + "  (" + str(len(data)) + " bytes)")

    # Optional syntax check if node is available
    node = shutil.which("node")
    if node:
        print("\nSyntax check (node -c):")
        allok = True
        for rel in written:
            p = os.path.join(repo, rel)
            r = subprocess.run([node, "-c", p], capture_output=True, text=True)
            if r.returncode == 0:
                print("  OK   " + rel)
            else:
                allok = False
                print("  FAIL " + rel + "\n" + r.stderr.strip())
        print("\n" + ("All files syntax-clean." if allok else "Some files failed syntax check!"))
    else:
        print("\n(node not found on PATH - skipped syntax check)")

    print("\n" + "=" * 63)
    print("DONE - the following bugs are fixed:")
    print(FIXES)
    print("Originals saved in: " + backup)
    print("Next: restart the agent, then replay/serve. A 4-6 match now shows")
    print("      0-1..4-6 with the correct scorer and green verified ticks.")
    print("=" * 63)


if __name__ == "__main__":
    main()
